def build_universal_questions(state_name, regulator_title, guaranty_name,
                               ce_hours, course_label):
    reg = regulator_title
    guar = guaranty_name
    st = state_name
    return [
        (f"Who is primarily responsible for regulating the insurance industry in {st}?",
         "multiple_choice", "standard",
         f"The {reg} is the chief regulator of insurance in {st}, responsible for licensing producers, approving policy forms and rates, and enforcing the state insurance laws.",
         [(f"The {reg}", True, f"Correct. The {reg} has broad authority to regulate all aspects of insurance in {st}."),
          ("The federal Department of Insurance", False, "There is no federal Department of Insurance. Insurance regulation is primarily a state function under the McCarran-Ferguson Act."),
          ("The National Association of Insurance Commissioners (NAIC)", False, "The NAIC is a standard-setting body for regulators but has no direct regulatory authority over insurers or producers."),
          ("The state attorney general", False, "The attorney general handles legal matters but the insurance regulator has primary jurisdiction over insurance regulation.")]),

        (f"Under {st} law, which of the following is an example of misrepresentation by an insurance producer?",
         "multiple_choice", "standard",
         "Misrepresentation is an unfair trade practice that includes making false or misleading statements about the terms, benefits, or conditions of an insurance policy.",
         [("Telling a client that a policy covers losses it does not actually cover", True, "Correct. Making false statements about policy coverage is misrepresentation — a prohibited unfair trade practice in every state."),
          ("Explaining to a client the differences between two competing policies", False, "Explaining policy differences accurately is legitimate sales practice, not misrepresentation."),
          ("Recommending a policy based on the client's stated financial needs", False, "Recommending suitable coverage based on client needs is proper producer duty."),
          ("Delivering a policy within the time required by state law", False, "Timely policy delivery is a producer obligation, not a prohibited practice.")]),

        (f"In {st}, rebating is best defined as:",
         "multiple_choice", "standard",
         "Rebating is offering or giving any valuable consideration as an inducement to purchase insurance. It is prohibited because it undermines the integrity of filed rates.",
         [("Offering anything of value as an inducement to purchase insurance", True, "Correct. Rebating is giving or promising any valuable consideration beyond the policy itself to induce an insurance purchase."),
          ("Charging a client more than the filed premium rate", False, "Charging above filed rates is overcharging, not rebating."),
          ("Replacing one policy with another without the client's consent", False, "Replacing a policy without consent through misrepresentation is twisting."),
          ("Splitting a commission with another licensed producer", False, "Commission sharing between licensed producers is generally permitted.")]),

        (f"An insurance producer in {st} who uses misrepresentation to persuade a policyholder to cancel an existing policy and purchase a new one is guilty of:",
         "multiple_choice", "standard",
         "Twisting is the use of misrepresentation to induce a policyholder to replace an existing policy. It is a prohibited unfair trade practice in all states.",
         [("Twisting", True, "Correct. Using misrepresentation to induce a policyholder to replace an existing policy is twisting."),
          ("Rebating", False, "Rebating involves giving something of value as an inducement to purchase, not misrepresentation to replace."),
          ("Defamation", False, "Defamation involves making false statements about another insurer or producer."),
          ("Churning", False, "Churning is replacement within the same company primarily for commission.")]),

        (f"Under {st} insurance law, a producer's license may be suspended or revoked for which of the following reasons?",
         "multiple_choice", "standard",
         "Insurance licenses may be suspended or revoked for misconduct including misappropriation of premiums, misrepresentation, and fraud.",
         [("Misappropriating client premium funds", True, "Correct. Misappropriating client premiums is a serious violation of fiduciary duty and grounds for license action in every state."),
          ("Failing the licensing exam on the first attempt", False, "Failing an exam is not grounds for license discipline."),
          ("Selling only one type of insurance product", False, "Specializing in one type of insurance is not a violation."),
          ("Recommending a competitor's product to a client", False, "Recommending a competitor's product is not a prohibited act.")]),

        (f"In {st}, when a licensed producer collects a premium payment from a client, those funds are considered:",
         "multiple_choice", "standard",
         "Premium funds collected by a producer must be held in a fiduciary capacity — the producer may not commingle them with personal or business funds.",
         [("Fiduciary funds that must be held separately from the producer's own money", True, "Correct. Collected premiums are fiduciary funds that must not be commingled with personal funds."),
          ("The producer's personal income until transmitted to the insurer", False, "Premium funds are never the producer's personal income."),
          ("Subject to a producer's lien until earned commissions are deducted", False, "Producers cannot retain premiums as a lien for commissions."),
          ("Unclaimed until the policy is formally issued", False, "Premium funds must be held as fiduciary property from the moment they are collected.")]),

        (f"The purpose of {st}'s insurance guaranty association is to:",
         "multiple_choice", "standard",
         f"The {guar} protects policyholders when a licensed insurer becomes insolvent, paying covered claims up to specified limits.",
         [(f"Pay covered claims when a licensed insurer becomes insolvent", True, f"Correct. The {guar} protects policyholders by paying covered claims when a licensed insurer is declared insolvent."),
          ("Regulate insurance rates to keep premiums affordable", False, "Rate regulation is the function of the state insurance regulator, not the guaranty association."),
          ("Provide reinsurance to small insurance companies", False, "Reinsurance is a private market function; the guaranty association does not provide reinsurance."),
          ("Manage the state's high-risk insurance pool", False, "High-risk pools are separate mechanisms from the guaranty association.")]),

        (f"Under {st} law, when a producer wants to replace a client's existing life insurance policy with a new one, the producer must:",
         "multiple_choice", "standard",
         "Replacement regulations require producers to provide written comparison documents and notify the existing insurer.",
         [("Provide a written comparison disclosure and notify the existing insurer", True, "Correct. Replacement regulations require comparison disclosures and notification to the insurer whose policy is being replaced."),
          ("Obtain written approval from the state insurance department", False, "State approval is not required for individual replacements."),
          ("Cancel the existing policy before placing the new policy", False, "The replacement should be in place before cancelling the existing policy."),
          ("Charge no commission on the replacement policy", False, "Commission restrictions are not a standard replacement regulation requirement.")]),

        (f"In {st}, a nonresident producer who is licensed in another state wants to obtain a {st} license. Generally, this producer:",
         "multiple_choice", "standard",
         "Most states grant nonresident licenses by reciprocity without requiring a separate exam for producers in good standing in their home state.",
         [("May be issued a nonresident license without taking the state exam if their home state offers reciprocity", True, "Correct. Most states waive the exam for nonresident applicants whose home state has a reciprocal licensing agreement."),
          ("Must take and pass the full state licensing exam regardless of home state license", False, "Most states waive the exam requirement for nonresident applicants with reciprocal home state licenses."),
          ("Must establish a business office in the state before receiving a license", False, "Nonresident producers are not required to maintain a physical office in the nonresident state."),
          ("Is exempt from all continuing education requirements in the nonresident state", False, "Nonresident producers may be subject to CE requirements.")]),

        (f"In {st}, which of the following activities constitutes coercion in the sale of insurance?",
         "multiple_choice", "standard",
         "Coercion is using threats, force, or economic pressure to compel someone to purchase insurance. It is a prohibited unfair trade practice.",
         [("Threatening to cancel a client's business contract unless they purchase insurance through you", True, "Correct. Using threats or economic pressure to compel an insurance purchase is coercion — a prohibited unfair trade practice."),
          ("Recommending a specific insurer based on financial strength ratings", False, "Recommending an insurer based on objective criteria is legitimate sales practice."),
          ("Explaining the penalties for driving without required auto insurance", False, "Explaining legal requirements is not coercion."),
          ("Offering a client a choice between two different policy options", False, "Offering policy choices is standard sales practice, not coercion.")]),

        (f"A {st} insurance producer's license must be renewed every:",
         "multiple_choice", "standard",
         f"Most states require license renewal every two years with continuing education requirements.",
         [("Two years, with continuing education requirements", True, f"Correct. Most states including {st} require license renewal every two years with required continuing education."),
          ("One year, without any continuing education requirement", False, "Annual renewal without CE is not the standard."),
          ("Five years, with no exam required at renewal", False, "5-year renewal cycles are not standard."),
          ("There is no renewal requirement once a license is issued", False, "All state insurance licenses require periodic renewal.")]),

        (f"Under {st} law, a temporary insurance license may be issued to:",
         "multiple_choice", "standard",
         "Temporary licenses are most commonly issued to allow continuity of an agency after the death or incapacitation of the licensed producer.",
         [("A surviving spouse or family member to continue an agency after the death of a licensed producer", True, "Correct. Temporary licenses are most commonly issued for agency continuity after death or incapacitation."),
          ("Any person who applies for a license while waiting for exam results", False, "Waiting for exam results does not qualify for a temporary license."),
          ("A person who failed the licensing exam and needs time to retake it", False, "Exam failure does not qualify for a temporary license."),
          ("Any unlicensed employee of an insurance agency", False, "Simply being employed by an agency does not qualify for a temporary license.")]),

        (f"In {st}, which of the following best describes an agent's express authority?",
         "multiple_choice", "standard",
         "Express authority is explicitly granted in writing through the agency agreement between the producer and the insurer.",
         [("Authority that is specifically granted in the written agency agreement", True, "Correct. Express authority is explicitly stated in the written contract between the producer and the insurer."),
          ("Authority that arises from the producer's position and normal business customs", False, "Authority arising from position and custom is implied authority."),
          ("Authority created when a third party reasonably believes the producer has authority based on the insurer's conduct", False, "Authority created by the insurer's conduct is apparent authority."),
          ("Authority that the producer assumes without any written agreement", False, "Assumed authority without written authorization is not a valid type of authority.")]),

        (f"Under {st} insurance law, defamation by an insurance producer is best defined as:",
         "multiple_choice", "standard",
         "Defamation is making false statements about another insurer or producer that injure their reputation. Truth is a complete defense.",
         [("Making false statements that injure the reputation of another insurer or producer", True, "Correct. Defamation is making false statements about another insurer or producer. Truthful statements are not defamation."),
          ("Accurately reporting a competitor's financial difficulties to a client", False, "Truthful statements are not defamation."),
          ("Failing to disclose a material fact about a policy to a client", False, "Failure to disclose is misrepresentation by omission, not defamation."),
          ("Using intimidation to prevent a client from shopping other insurers", False, "Using intimidation is coercion, not defamation.")]),
    ]


def build_semi_universal(state_name, regulator_title, guaranty_name,
                          ce_hours, course_label):
    st = state_name
    reg = regulator_title
    return [
        (f"A {st} insurance producer who moves to a new address must notify the {reg} within:",
         "multiple_choice", "standard",
         "Most states require producers to notify the regulator of address changes within 30 days.",
         [("30 days of the address change", True, f"Correct. Most states require notification of address changes within 30 days."),
          ("5 business days", False, "5 business days is shorter than the standard requirement."),
          ("60 days", False, "60 days exceeds the typical requirement."),
          ("At the next license renewal", False, "Address changes must be reported promptly, not deferred until renewal.")]),

        (f"In {st}, continuing education requirements for licensed insurance producers typically include:",
         "multiple_choice", "standard",
         "Most states require CE hours per renewal cycle including a required ethics component.",
         [(f"A specified number of hours including an ethics component", True, "Correct. Most states require a minimum number of CE hours with a required ethics component."),
          ("Only product knowledge courses with no ethics requirement", False, "Ethics is a required component of CE in virtually all states."),
          ("CE is optional — only required if the producer had a complaint filed", False, "CE is a mandatory renewal requirement."),
          ("A state exam retake every renewal cycle", False, "Retaking the exam is not a CE requirement.")]),

        (f"Under {st} law, an insurance producer who is convicted of a felony must:",
         "multiple_choice", "standard",
         "Most states require producers to report criminal convictions to the state insurance regulator within a specified timeframe.",
         [("Report the conviction to the state insurance regulator within the required timeframe", True, "Correct. Most states require reporting of felony convictions to the regulator."),
          ("Immediately surrender their license without any hearing", False, "A conviction triggers reporting requirements and may lead to a hearing but not automatic immediate surrender."),
          ("Only report the conviction if it relates to financial crimes", False, "Most states require reporting of all felony convictions."),
          ("Wait until the conviction is final before reporting", False, "Most states require reporting upon conviction.")]),

        (f"In {st}, which entity must give prior approval before an insurance producer can use advertising materials?",
         "multiple_choice", "standard",
         "The insurer must review and approve advertising materials used by its producers to ensure compliance with state regulations.",
         [("The insurer the producer represents", True, "Correct. The insurer must review and approve producer advertising materials."),
          ("The state insurance department must pre-approve all advertisements", False, "Pre-approval by the state department is not required for most lines."),
          ("A national advertising standards board", False, "There is no national advertising standards board for insurance."),
          ("No approval is needed — producers may advertise freely", False, "Insurance advertising is regulated; insurer approval is typically required.")]),

        (f"The {guaranty_name} covers claims when:",
         "multiple_choice", "standard",
         f"The guaranty association covers claims when a licensed (admitted) insurer becomes insolvent — not when unlicensed insurers fail.",
         [(f"A licensed admitted insurer is declared insolvent", True, f"Correct. The guaranty association covers claims when a licensed insurer becomes insolvent."),
          ("A claim is denied by any insurer for any reason", False, "The guaranty association only covers insolvency situations."),
          ("A policyholder cannot afford to pay their premium", False, "Premium affordability is not a triggering condition."),
          ("An unauthorized insurer fails to pay claims", False, "The guaranty association covers only licensed admitted insurer failures.")]),

        (f"Under {st} law, a producer who shares a commission with an unlicensed person:",
         "multiple_choice", "standard",
         "Sharing commissions with unlicensed individuals is prohibited and grounds for license discipline in all states.",
         [("Violates state insurance law and may have their license suspended or revoked", True, "Correct. Sharing commissions with unlicensed persons is prohibited."),
          ("Is permitted as long as the unlicensed person performed legitimate services", False, "Services performed do not authorize commission sharing with unlicensed persons."),
          ("Must report the sharing arrangement to the state insurance department", False, "The arrangement itself is prohibited; disclosure does not make it permissible."),
          ("Is only permitted if the unlicensed person is a family member", False, "Family relationships do not create an exception to this prohibition.")]),
    ]


