    ("LA", "Louisiana", "Commissioner of Insurance",
     "Louisiana Life and Health Insurance Guaranty Association", 24),
    ("ME", "Maine", "Superintendent of Insurance",
     "Maine Life and Health Insurance Guaranty Association", 24),
    ("MD", "Maryland", "Insurance Commissioner",
     "Maryland Life and Health Insurance Guaranty Corporation", 24),
    ("MA", "Massachusetts", "Commissioner of Insurance",
     "Massachusetts Life and Health Insurance Guaranty Fund", 24),
    ("MI", "Michigan", "Director of Insurance and Financial Services",
     "Michigan Life and Health Insurance Guaranty Association", 24),
    ("MN", "Minnesota", "Commissioner of Commerce",
     "Minnesota Life and Health Insurance Guaranty Association", 24),
